+        MessageRole::Agent => "assistant".to_string(),
+        MessageRole::Tool => "tool".to_string(),
+        MessageRole::System => "system".to_string(),
+        MessageRole::Other(value) => {
+            let lowered = value.trim().to_ascii_lowercase();
+            if lowered.is_empty() {
+                "user".to_string()
+            } else {
+                lowered
+            }
+        }
+    }
